import{_ as e,c as a,o,ag as s}from"./chunks/framework.DD2hp6gW.js";const r="/assets/settings-product-percentage-format.BVrhyQ75.png",i="/assets/settings-product-fixed-format.BiS0FBzh.png",n="/assets/settings-product-bogo-format.DaEAqFtL.png",d="/assets/settings-product-bogo-advanced-format.Pni5b8jZ.png",c="/assets/settings-product-quantity-table.CCcPzxdI.png",u="/assets/settings-customize-table-modal.BxD4Z7e4.png",l="/assets/settings-product-exclusion.B8neNGk9.png",p="/assets/settings-product-priority-dropdown.Dls-4Tm8.png",x=JSON.parse('{"title":"Product Settings","description":"","frontmatter":{},"headers":[],"relativePath":"settings/product-settings.md","filePath":"settings/product-settings.md","lastUpdated":1769871666000}'),g={name:"settings/product-settings.md"};function h(m,t,b,y,f,_){return o(),a("div",null,t[0]||(t[0]=[s('<h1 id="product-settings" tabindex="-1">Product Settings <a class="header-anchor" href="#product-settings" aria-label="Permalink to &quot;Product Settings&quot;">​</a></h1><p>The <strong>Product Settings</strong> tab controls how discounts and promotional messaging appear on your individual product pages.</p><h2 id="message-formats" tabindex="-1">Message Formats <a class="header-anchor" href="#message-formats" aria-label="Permalink to &quot;Message Formats&quot;">​</a></h2><p>Customize how promotional messages are displayed on product pages for different campaign types.</p><h3 id="percentage-schedule-early-bird-discount" tabindex="-1">Percentage Schedule / Early Bird Discount <a class="header-anchor" href="#percentage-schedule-early-bird-discount" aria-label="Permalink to &quot;Percentage Schedule / Early Bird Discount&quot;">​</a></h3><p><img src="'+r+'" alt="Percentage Schedule Message Format"></p><p><strong>Placeholder:</strong> <code>{percentage_off}</code> — The percentage discount value.</p><p><strong>Example:</strong> <code>You save {percentage_off}%</code></p><h3 id="fixed-schedule-early-bird-discount" tabindex="-1">Fixed Schedule / Early Bird Discount <a class="header-anchor" href="#fixed-schedule-early-bird-discount" aria-label="Permalink to &quot;Fixed Schedule / Early Bird Discount&quot;">​</a></h3><p><img src="'+i+'" alt="Fixed Schedule Message Format"></p><p><strong>Placeholder:</strong> <code>{amount_off}</code> — The fixed amount discount.</p><p><strong>Example:</strong> <code>You save {amount_off} per item</code></p><h3 id="bogo-discount" tabindex="-1">BOGO Discount <a class="header-anchor" href="#bogo-discount" aria-label="Permalink to &quot;BOGO Discount&quot;">​</a></h3><p><img src="'+n+'" alt="BOGO Discount Message Format"></p><table tabindex="0"><thead><tr><th>Placeholder</th><th>Description</th></tr></thead><tbody><tr><td><code>{buy_quantity}</code></td><td>Quantity customer must buy</td></tr><tr><td><code>{get_quantity}</code></td><td>Quantity customer receives</td></tr></tbody></table><p><strong>Example:</strong> <code>Buy {buy_quantity} and get {get_quantity} free!!!!!!</code></p><h3 id="bogo-advanced-discount" tabindex="-1">BOGO Advanced Discount <a class="header-anchor" href="#bogo-advanced-discount" aria-label="Permalink to &quot;BOGO Advanced Discount&quot;">​</a></h3><p><img src="'+d+'" alt="BOGO Advanced Message Format"></p><table tabindex="0"><thead><tr><th>Placeholder</th><th>Description</th></tr></thead><tbody><tr><td><code>{buy_quantity}</code></td><td>Quantity customer must buy</td></tr><tr><td><code>{get_quantity}</code></td><td>Quantity customer receives</td></tr><tr><td><code>{free_product_name}</code></td><td>Name of the free product</td></tr></tbody></table><p><strong>Example:</strong> <code>Buy {buy_quantity} and {get_quantity} {free_product_name} free!</code></p><hr><h2 id="quantity-discounts-table" tabindex="-1">Quantity Discounts Table <a class="header-anchor" href="#quantity-discounts-table" aria-label="Permalink to &quot;Quantity Discounts Table&quot;">​</a></h2><p><img src="'+c+'" alt="Enable Quantity Discounts Table"></p><h3 id="enable-quantity-discounts-table-on-product-page" tabindex="-1">Enable Quantity Discounts Table on Product Page <a class="header-anchor" href="#enable-quantity-discounts-table-on-product-page" aria-label="Permalink to &quot;Enable Quantity Discounts Table on Product Page&quot;">​</a></h3><p>When enabled, a pricing table showing tiered discounts will appear on product pages for Quantity-based campaigns.</p><h3 id="customize-discount-table" tabindex="-1">Customize Discount Table <a class="header-anchor" href="#customize-discount-table" aria-label="Permalink to &quot;Customize Discount Table&quot;">​</a></h3><p>Click <strong>Customize Table</strong> to open the configuration modal:</p><p><img src="'+u+'" alt="Customize Discount Table Modal"></p><table tabindex="0"><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td><strong>Show Table Header</strong></td><td>Toggle visibility of column header row</td></tr><tr><td><strong>Title Column</strong></td><td>Enable/disable and customize the campaign title column</td></tr><tr><td><strong>Range Column</strong></td><td>Enable/disable and customize the quantity range column</td></tr><tr><td><strong>Discount Column</strong></td><td>Enable/disable, customize label, and choose content (Price/Percentage)</td></tr></tbody></table><p>The <strong>Preview</strong> section shows a live preview of how the table will appear.</p><hr><h2 id="product-exclusion-prioritization" tabindex="-1">Product Exclusion &amp; Prioritization <a class="header-anchor" href="#product-exclusion-prioritization" aria-label="Permalink to &quot;Product Exclusion &amp; Prioritization&quot;">​</a></h2><p><img src="'+l+'" alt="Product Exclusion &amp; Prioritization"></p><h3 id="product-page-discount-message-format" tabindex="-1">Product Page Discount Message Format <a class="header-anchor" href="#product-page-discount-message-format" aria-label="Permalink to &quot;Product Page Discount Message Format&quot;">​</a></h3><p><img src="'+p+'" alt="Product Priority Dropdown"></p><p>Defines the logic when multiple discounts could apply to the same product:</p><table tabindex="0"><thead><tr><th>Option</th><th>Behavior</th></tr></thead><tbody><tr><td><strong>Apply Highest Discount</strong></td><td>Uses the campaign giving the biggest price reduction</td></tr><tr><td><strong>Apply Lowest Discount</strong></td><td>Uses the campaign giving the smallest price reduction</td></tr><tr><td><strong>Apply First Match</strong></td><td>Applies the first matching campaign by priority order</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">INFO</p><p>This setting only applies when campaign stacking is disabled. If stacking is enabled, discounts can be layered according to the stacking rules.</p></div><hr><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>Continue exploring the settings for cart and stacking logic.</p><ul><li><strong><a href="./cart-settings.html">Cart Settings →</a></strong></li></ul>',42)]))}const q=e(g,[["render",h]]);export{x as __pageData,q as default};
